try {
  const body = items[0].json.body || items[0].json;

  // Validate required fields
  if (!body.avg_heart_rate || !body.resting_heart_rate) {
    throw new Error('Missing critical health data');
  }

  const hr = body.avg_heart_rate;
  const rhr = body.resting_heart_rate;
  const steps = body.total_steps ?? 5000;
  const sleep = body.avg_sleep_duration ?? 420;
  const activity = body.activity_level ?? 'low';

  let stressScore = 0;

  // 1. Heart Rate Ratio (Main Signal)
  const hrRatio = hr / rhr;
  if (hrRatio >= 1.6) stressScore += 45;
  else if (hrRatio >= 1.3) stressScore += 30;
  else if (hrRatio >= 1.1) stressScore += 15;
  else stressScore += 5;

  // 2. Sleep Impact
  if (sleep < 240) stressScore += 30;
  else if (sleep < 360) stressScore += 20;
  else if (sleep < 420) stressScore += 10;

  // 3. Activity Context
  if (activity === 'high') stressScore -= 10;
  else if (activity === 'moderate') stressScore -= 5;
  else stressScore += 15;

  // 4. Steps / Movement
  if (steps < 2000) stressScore += 15;
  else if (steps < 5000) stressScore += 10;

  // Normalize score
  stressScore = Math.max(0, Math.min(100, Math.round(stressScore)));

  let level = 'low';
  let recommendation = 'You are maintaining a good balance. Keep it up.';

  if (stressScore > 75) {
    level = 'high';
    recommendation = 'High stress detected. Take a break, hydrate, and try breathing exercises.';
  } else if (stressScore > 45) {
    level = 'moderate';
    recommendation = 'Moderate stress. A short walk or relaxation may help.';
  }

  return [{
    json: {
      success: true,
      input_summary: {
        hr,
        rhr,
        steps,
        sleep,
        activity
      },
      stress_score: stressScore,
      stress_level: level,
      recommendation
    }
  }];

} catch (error) {
  return [{
    json: {
      success: false,
      error: error.message
    }
  }];
}
